class Solution {
    public int racecar(int target) {
        int position = 0;
        int speed = 1;
        int steps = 0;
        while (position != target) {
            position += speed;
            steps++;
            if (position > target) {
                speed = -1;
            } else if (position < target) {
                speed *= 2;
            }
        }
        return steps;
    }
}
```
